// Node 5: Enhanced processing with clean dates, tracking categories, and 2025 filtering
const journalsData = $json;

let transactions = [];

for (const journal of journalsData.Journals || []) {
  // Convert Xero date format to readable date and extract year
  let cleanDate = '';
  let journalYear = null;

  if (journal.JournalDate) {
    const timestamp = journal.JournalDate.match(/\d+/);
    if (timestamp) {
      const date = new Date(parseInt(timestamp[0]));
      cleanDate = date.toISOString().split('T')[0];
      journalYear = date.getFullYear();
    }
  }

  // Only process 2025 transactions (change from 2024 to 2025)
  if (journalYear === 2025) {
    for (const line of journal.JournalLines || []) {
      // Extract tracking category info cleanly
      let trackingRegion = '';
      let trackingCategory = '';
      if (line.TrackingCategories && line.TrackingCategories !== '[]') {
        try {
          const tracking = JSON.parse(line.TrackingCategories);
          if (tracking.length > 0) {
            trackingCategory = tracking[0].Name || '';
            trackingRegion = tracking[0].Option || '';
          }
        } catch (e) {
          // Handle parsing errors gracefully
        }
      }

      transactions.push({
        Date: cleanDate,
        JournalNumber: journal.JournalNumber,
        JournalID: journal.JournalID,
        AccountID: line.AccountID,
        AccountCode: line.AccountCode,
        AccountName: line.AccountName,
        AccountType: line.AccountType,
        Description: line.Description || '',
        NetAmount: line.NetAmount || 0,
        GrossAmount: line.GrossAmount || 0,
        TaxAmount: line.TaxAmount || 0,
        TaxType: line.TaxType || '',
        TaxName: line.TaxName || '',
        TrackingCategory: trackingCategory,
        TrackingRegion: trackingRegion
      });
    }
  }
}

console.log(`Processed ${transactions.length} transactions from 2025`);

return transactions;

// Node 6: Aggregate all transactions and convert to CSV
const allItems = $input.all(); // Get all items from previous node
let transactions = [];

console.log(`Number of input items: ${allItems.length}`);

// Collect all transactions from all executions
for (const item of allItems) {
  console.log(`Item type: ${typeof item.json}, Is array: ${Array.isArray(item.json)}`);

  if (Array.isArray(item.json)) {
    transactions.push(...item.json);
    console.log(`Added ${item.json.length} transactions from array`);
  } else {
    transactions.push(item.json);
    console.log(`Added 1 transaction from object`);
  }
}

console.log(`Total transactions collected: ${transactions.length}`);

// CSV headers
const headers = [
  'Date', 'JournalNumber', 'JournalID', 'AccountID', 'AccountCode',
  'AccountName', 'AccountType', 'Description', 'NetAmount', 'GrossAmount',
  'TaxAmount', 'TaxType', 'TaxName', 'TrackingCategory', 'TrackingRegion'
];

// CSV escape function
function escapeCSV(value) {
  if (value === null || value === undefined) return '';
  const str = String(value);
  if (str.includes(',') || str.includes('"') || str.includes('\n') || str.includes('\r')) {
    return '"' + str.replace(/"/g, '""') + '"';
  }
  return str;
}

// Build CSV
let csvContent = headers.join(',') + '\n';
for (const transaction of transactions) {
  const row = headers.map(header => escapeCSV(transaction[header]));
  csvContent += row.join(',') + '\n';
}

return {
  csv: csvContent,
  filename: `xero_account_transactions_${new Date().toISOString().split('T')[0]}.csv`,
  recordCount: transactions.length,
  headers: headers
};

